/* ── PULL QUOTE ── */
function PullQuote({ text, cat }) {
  const col = CAT_COLORS[cat] || "#C41A1A";
  return (
    <div style={{padding:"22px 20px",margin:"0 0 18px",background:`linear-gradient(135deg,${col}08,rgba(0,0,0,0))`,border:`1px solid ${col}22`,borderLeft:`3px solid ${col}`,borderRadius:"0 8px 8px 0",backdropFilter:"blur(12px)",breakInside:"avoid"}}>
      <div style={{fontFamily:"'Instrument Serif',Georgia,serif",fontStyle:"italic",fontSize:"1.05rem",lineHeight:1.6,color:"rgba(242,232,213,0.75)",marginBottom:8}}>"{text}"</div>
      <div style={{fontSize:"0.52rem",color:col,letterSpacing:"0.12em",textTransform:"uppercase",fontFamily:"'Azeret Mono',monospace"}}>— Anonymous · {cat}</div>
    </div>
  );
}

